def perceive(data):
    text = data if isinstance(data, str) else str(data)
    fields = {}
    for token in text.replace(",", " ").split():
        if "=" in token:
            k, v = token.split("=", 1)
            fields[k.strip()] = v.strip()
    try:
        sev = int(fields.get("severity", "1"))
    except (ValueError, TypeError):
        sev = 1
    return {
        "candidate_source": fields.get("src") or fields.get("source") or "unknown",
        "candidate_type": fields.get("type") or fields.get("event") or "generic",
        "candidate_severity": max(1, min(5, sev)),
    }
